    # Extract resources from the bundle (standard FHIR bundle structure)
    entries = bundle.get("entry", [])
    for entry in entries:
        resource = entry.get("resource", {})
        if resource.get("resourceType") == "Procedure":
            all_entries.append(resource)
    # Check for pagination – follow the 'next' link if present
    next_link = None
    for link in bundle.get("link", []):
        if link.get("relation") == "next":
            next_link = link.get("url")
            break
    if not next_link:
        break
    # Update URL for the next page (FHIR pagination uses absolute URLs)
    url = next_link
    params = {}  # pagination URLs already contain query parameters

