# Helper to obtain a readable identifier for a MedicationRequest

def _request_identifier(req: dict) -> str:
    # Prefer the FHIR resource id
    if "id" in req:
        return req["id"]
    # Fallback to medication coding or display name
    med_info = req.get("medicationCodeableConcept")
    if med_info:
        # Try coding code
        for coding in med_info.get("coding", []):
            code = coding.get("code")
            if code:
                return code
        # Try display/text fields
        display = med_info.get("text") or med_info.get("display")
        if display:
            return display
    # Finally, try medicationReference.display
    ref = req.get("medicationReference", {})
    display = ref.get("display")
    if display:
        return display
    # As a last resort, return a placeholder
    return "unknown"

