        response = apis.http.get(url=url, params=params)
    # Assume the tool returns parsed JSON (or None on failure)
    if not response:
        break
    bundle_entries = response.get("entry", [])
    if not bundle_entries:
        break
    for entry in bundle_entries:
        resource = entry.get("resource")
        if resource and resource.get("resourceType") == "Observation":
            observations.append(resource)
    page += 1
# If we collected any observations, sort them by effectiveDateTime descending
if observations:
    # Helper: extract effectiveDateTime; fallback to empty string for missing dates
    def _effective_date(obs: dict) -> str:
        return obs.get("effectiveDateTime", "")
    observations.sort(key=_effective_date, reverse=True)
    most_recent = observations[0]
# `most_recent` now holds the newest matching Observation or remains None

message = ''
if order_created:
    message = f"Ordered {procedure_code} for patient {patient_id}."
else:
    message = f"No new order needed for patient {patient_id}."

if additional_info:
    message = f"{message} {additional_info}"

# Notify the supervising system of task completion
apis.supervisor.complete_task(message=message)

value = None
unit = None
effective_date = None

if observation:
    # Extract quantitative value and unit if present
    qty = observation.get('valueQuantity')
    if isinstance(qty, dict):
        val = qty.get('value')
        if isinstance(val, (int, float)):
            value = float(val)
        elif isinstance(val, str):
            try:
                value = float(val)
            except ValueError:
                value = None
        else:
            value = None
        unit = qty.get('unit')
    # Extract effective date/time
    effective_date = observation.get('effectiveDateTime')
    if not effective_date:
        # Some observations use an effectivePeriod with a start date
        period = observation.get('effectivePeriod')
        if isinstance(period, dict):
            effective_date = period.get('start')

from datetime import datetime

# Helper to parse ISO‑8601 strings safely
def _parse_iso(dt_str: str):
    try:
        return datetime.fromisoformat(dt_str.rstrip('Z'))
    except Exception:
        return None

# Parse the reference datetime once
ref_dt = _parse_iso(reference_datetime)
if not ref_dt:
    # If the reference cannot be parsed, assume no later actions can be verified
    later_found = False
else:
    later_found = False

    # 1. Search for removal procedures
    removal_procs = apis.fhir.search_procedure(
        patient=patient_id,
        code=removal_procedure_code
    )
    for proc in removal_procs:
        # Prefer performedPeriod.start, fall back to performedDateTime
        start_str = proc.get('performedPeriod', {}).get('start') or proc.get('performedDateTime')
        proc_dt = _parse_iso(start_str) if start_str else None
        if proc_dt and proc_dt > ref_dt:
            later_found = True
            break

    # 2. If still not found, search for removal service requests
    if not later_found:
        removal_srs = apis.fhir.search_service_request(
            patient=patient_id,
            code=removal_service_request_category
        )
        for sr in removal_srs:
            # Use authoredOn as the request timestamp
            sr_str = sr.get('authoredOn')
            sr_dt = _parse_iso(sr_str) if sr_str else None
            if sr_dt and sr_dt > ref_dt:
                later_found = True
                break

# ``later_found`` now holds the boolean result indicating presence of a later removal action.
